export function script(input) {
  const packageSpecs = Array.isArray(input.packageSpecs) ? input.packageSpecs.map(String) : [];
  const osvFindings = Array.isArray(input.findings) ? input.findings : [];
  const packages = Array.isArray(input.packages) ? input.packages : [];
  const summary = input.summary && typeof input.summary === 'object' ? input.summary : {};
  const registryRecords = Array.isArray(input.registryRecords) ? input.registryRecords : [];
  const registryRiskSignals = Array.isArray(input.registryRiskSignals) ? input.registryRiskSignals : [];
  const registrySummary = input.registrySummary && typeof input.registrySummary === 'object' ? input.registrySummary : {};
  const registryWarnings = Array.isArray(input.registryWarnings) ? input.registryWarnings.map(String) : [];
  const severityRank = { critical: 5, high: 4, medium: 3, low: 2, unknown: 1 };
  const signalSeverityToCwe = { 'install-script': 'CWE-506', deprecated: 'CWE-review-required', 'missing-repository': 'CWE-review-required', 'recent-publish': 'CWE-review-required', 'typosquat-similarity': 'CWE-506' };
  const candidates = [];
  for (const finding of osvFindings) {
    if (finding?.isMaliciousPackageRecord === true || String(finding?.id || '').startsWith('MAL-') || /malicious/i.test(String(finding?.summary || ''))) {
      candidates.push({
        title: `Malicious npm advisory: ${finding.packageName || finding.id}`,
        severity: 'critical',
        cweGuess: 'CWE-506',
        product: finding.packageName || null,
        affectedVersions: finding.version ? [finding.version] : [],
        impactSummary: finding.summary || 'OSV malicious-package record - immediate escalation.',
        evidence: { source: 'osv', id: finding.id, aliases: finding.aliases || [], references: (finding.references || []).slice(0, 5) },
        reproOutline: ['Confirm package is not installed in authorized environments', 'Review OSV/GHSA references', 'Report via npm/GitHub Security Advisory process if novel'],
        suggestedCnaPath: 'GitHub Security Advisory or npm security contact for malicious package records',
        mitreCveRequestNotes: 'Malicious package - may map to GHSA rather than traditional CVE',
        priorityScore: 120,
        priorityReasons: ['OSV malicious-package record']
      });
    }
  }
  const signalsByPackage = new Map();
  for (const signal of registryRiskSignals) {
    const packageName = String(signal?.packageName || '').trim();
    if (!packageName) continue;
    const list = signalsByPackage.get(packageName) || [];
    list.push(signal);
    signalsByPackage.set(packageName, list);
  }
  for (const [packageName, signals] of signalsByPackage.entries()) {
    const record = registryRecords.find((item) => item?.name === packageName) || {};
    const severity = signals.some((item) => item.severity === 'high') ? 'high' : signals.some((item) => item.severity === 'medium') ? 'medium' : 'low';
    const priorityScore = Math.round(signals.reduce((total, item) => total + Number(item.score || 0), 0) * 10) / 10;
    const signalNames = signals.map((item) => item.signal).filter(Boolean);
    candidates.push({
      title: `Registry precursor signals for ${packageName}`,
      severity,
      cweGuess: signalNames.includes('install-script') || signalNames.includes('typosquat-similarity') ? 'CWE-506' : (signalSeverityToCwe[signalNames[0]] || 'CWE-review-required'),
      product: packageName,
      affectedVersions: record.analyzedVersion ? [record.analyzedVersion] : record.latest ? [record.latest] : [],
      impactSummary: 'npm registry metadata shows supply-chain precursor signals requiring manual validation.',
      evidence: { source: 'npm-registry', latest: record.latest || null, analyzedVersion: record.analyzedVersion || null, repository: record.repositoryUrl || null, maintainers: (record.maintainers || []).slice(0, 5), signals: signals.map((item) => ({ signal: item.signal, severity: item.severity, rationale: item.rationale, evidence: item.evidence || {} })) },
      reproOutline: ['Inspect package tarball and lifecycle scripts in an isolated environment', 'Compare maintainer history and publication timeline', 'Check for dependency confusion or typosquat against internal package names'],
      suggestedCnaPath: 'Report suspicious packages via npm security or GitHub Security Advisory',
      mitreCveRequestNotes: 'Supply-chain precursor - confirm malicious intent before CVE/GHSA submission',
      priorityScore,
      priorityReasons: signals.map((item) => item.rationale || item.signal).filter(Boolean)
    });
  }
  const ranked = candidates.sort((a, b) => b.priorityScore - a.priorityScore || (severityRank[b.severity] || 0) - (severityRank[a.severity] || 0)).slice(0, 50);
  const highestSeverity = ranked.reduce((current, item) => (severityRank[item.severity] || 0) > (severityRank[current] || 0) ? item.severity : current, null);
  return {
    brief: {
      summary: {
        candidateCount: ranked.length,
        highestSeverity,
        topCandidate: ranked[0]?.title || null,
        packagesChecked: Number(summary.packagesChecked || registrySummary.packagesChecked || packageSpecs.length),
        osvFindings: osvFindings.length,
        maliciousPackageRecords: Number(summary.maliciousPackageRecords || 0),
        registryRecordsFetched: Number(registrySummary.recordsFetched || registryRecords.length),
        registryRiskSignals: Number(registrySummary.riskSignals || registryRiskSignals.length)
      },
      authorizationNotes: input.researchNotes || null,
      packages: packages.slice(0, 100),
      registryRecords: registryRecords.slice(0, 100),
      registryWarnings,
      candidates: ranked,
      nextSteps: ['Confirm novelty', 'Contact vendor CNA or npm/GitHub security for malicious-package reports', 'Prepare MITRE CVE form if no CNA and issue qualifies as a vulnerability']
    }
  };
}
